1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const DEDUCTIBLE = 100;
5	
6	const INSURANCE_VALUES: Record<string, number> = {
7	  sword: 1000,
8	  amulet: 600,
9	  staff: 800,
10	  potion: 400,
11	  rune: 250,
12	  moonstone: 250,
13	};
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
27	
28	const basePremium = (item: any): number =>
29	  BASE_PREMIUMS[item.type] ?? 0;
30	
31	const countByType = (items: any[]): Record<string, number> => {
32	  const counts: Record<string, number> = {};
33	  for (const item of items) {
34	    counts[item.type] = (counts[item.type] ?? 0) + 1;
35	  }
36	  return counts;
37	};
38	
39	const componentGroupPremium = (type: string, count: number): number =>
40	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
41	
42	const itemSurcharges = (item: any, base: number): number =>
43	  (item.cursed ? base * 0.5 : 0) + (item.enchantment >= 5 ? base * 0.3 : 0);
44	
45	const policyWideModifiers = (policyBase: number, customer: any, quoteIndex: number): number => {
46	  const firstInsurance = policyBase * 0.1;
47	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? -policyBase * 0.2 : 0;
48	  const followUpDiscount = quoteIndex > 0 ? -policyBase * 0.15 : 0;
49	  return firstInsurance + loyaltyDiscount + followUpDiscount;
50	};
51	
52	const quotePremium = (items: any[], customer: any, quoteIndex: number): number => {
53	  for (const item of items) {
54	    if (!(item.type in BASE_PREMIUMS)) {
55	      throw new Error(`Unknown item type: ${item.type}`);
56	    }
57	  }
58	  const components = items.filter(isComponent);
59	  const nonComponents = items.filter((item: any) => !isComponent(item));
60	  const componentTotal = Object.entries(countByType(components)).reduce(
61	    (sum: number, [type, count]: [string, number]) => sum + componentGroupPremium(type, count),
62	    0,
63	  );
64	  const { nonComponentBase, surchargesTotal } = nonComponents.reduce(
65	    (acc, item: any) => {
66	      const base = basePremium(item);
67	      return {
68	        nonComponentBase: acc.nonComponentBase + base,
69	        surchargesTotal: acc.surchargesTotal + itemSurcharges(item, base),
70	      };
71	    },
72	    { nonComponentBase: 0, surchargesTotal: 0 },
73	  );
74	  const policyBasePremium = nonComponentBase + componentTotal;
75	  const adjustedPremium = policyBasePremium + surchargesTotal + policyWideModifiers(policyBasePremium, customer, quoteIndex);
76	  return Math.ceil(adjustedPremium + PROCESSING_FEE);
77	};
78	
79	const insuranceSum = (items: any[]): number =>
80	  items.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
81	
82	const damageReimbursement = (damage: any, policyItem: any): number => {
83	  const amount = policyItem && policyItem.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
84	  return Math.max(0, amount - DEDUCTIBLE);
85	};
86	
87	const processClaim = (step: any, policy: any, remainingCap: number): any => {
88	  const damageCounts: Record<string, number> = {};
89	  for (const damage of step.incident.damages) {
90	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
91	  }
92	  const policyCounts: Record<string, number> = {};
93	  for (const item of policy.items) {
94	    policyCounts[item.type] = (policyCounts[item.type] ?? 0) + 1;
95	  }
96	  for (const [type, count] of Object.entries(damageCounts)) {
97	    if (count > (policyCounts[type] ?? 0)) {
98	      throw new Error(`More damages of type ${type} than policy covers`);
99	    }
100	  }
101	  const totalPayout = step.incident.damages.reduce(
102	    (sum: number, damage: any) => {
103	      const policyItem = policy.items.find((item: any) => item.type === damage.itemType);
104	      if (!policyItem) {
105	        throw new Error(`Item type not in policy: ${damage.itemType}`);
106	      }
107	      if (damage.amount < 0) {
108	        throw new Error(`Negative damage amount: ${damage.amount}`);
109	      }
110	      return sum + damageReimbursement(damage, policyItem);
111	    },
112	    0,
113	  );
114	  const clampedPayout = Math.min(totalPayout, remainingCap);
115	  const payout = Math.floor(clampedPayout);
116	  return { payout, remainingCap: remainingCap - payout };
117	};
118	
119	export const processScenario = (scenario: any): any => {
120	  const policies: Record<number, any> = {};
121	  const caps: Record<number, number> = {};
122	  let quoteIndex = 0;
123	  return {
124	    results: scenario.steps.map((step: any, index: number) => {
125	      if (step.op === "claim") {
126	        const policyIndex = step.policy;
127	        if (caps[policyIndex] === undefined) {
128	          caps[policyIndex] = insuranceSum(policies[policyIndex].items) * 2;
129	        }
130	        const result = processClaim(step, policies[policyIndex], caps[policyIndex]);
131	        caps[policyIndex] = result.remainingCap;
132	        return result;
133	      }
134	      policies[index] = step;
135	      const result = { premium: quotePremium(step.items, scenario.customer, quoteIndex) };
136	      quoteIndex++;
137	      return result;
138	    }),
139	  };
140	};
