87	const countDamagesByType = (damages: any[]): Record<string, number> => {
88	  const counts: Record<string, number> = {};
89	  for (const damage of damages) {
90	    counts[damage.itemType] = (counts[damage.itemType] ?? 0) + 1;
91	  }
92	  return counts;
93	};
94	
95	const validateDamageCounts = (damages: any[], policyItems: any[]): void => {
96	  const damageCounts = countDamagesByType(damages);
97	  const policyCounts = countByType(policyItems);
98	  for (const [type, count] of Object.entries(damageCounts)) {
99	    if (count > (policyCounts[type] ?? 0)) {
100	      throw new Error(`More damages of type ${type} than policy covers`);
101	    }
102	  }
103	};
104	
105	const validateDamages = (damages: any[], policyItems: any[]): void => {
106	  for (const damage of damages) {
107	    if (!policyItems.some((item: any) => item.type === damage.itemType)) {
108	      throw new Error(`Item type not in policy: ${damage.itemType}`);
109	    }
110	    if (damage.amount < 0) {
111	      throw new Error(`Negative damage amount: ${damage.amount}`);
112	    }
113	  }
114	};
115	
116	const findPolicyItem = (policyItems: any[], itemType: string): any =>
117	  policyItems.find((item: any) => item.type === itemType);
118	
119	const processClaim = (step: any, policy: any, remainingCap: number): any => {
120	  validateDamageCounts(step.incident.damages, policy.items);
121	  validateDamages(step.incident.damages, policy.items);
122	  const totalPayout = step.incident.damages.reduce(
123	    (sum: number, damage: any) =>
124	      sum + damageReimbursement(damage, findPolicyItem(policy.items, damage.itemType)),
125	    0,
126	  );
127	  const clampedPayout = Math.min(totalPayout, remainingCap);
128	  const payout = Math.floor(clampedPayout);
129	  return { payout, remainingCap: remainingCap - payout };
130	};
131	
132	export const processScenario = (scenario: any): any => {
133	  const policies: Record<number, any> = {};
134	  const caps: Record<number, number> = {};
135	  let quoteIndex = 0;
136	  return {
137	    results: scenario.steps.map((step: any, index: number) => {
138	      if (step.op === "claim") {
139	        const policyIndex = step.policy;
140	        if (caps[policyIndex] === undefined) {
141	          caps[policyIndex] = insuranceSum(policies[policyIndex].items) * 2;
142	        }
143	        const result = processClaim(step, policies[policyIndex], caps[policyIndex]);
144	        caps[policyIndex] = result.remainingCap;
145	        return result;
146	      }
147	      policies[index] = step;
148	      const result = { premium: quotePremium(step.items, scenario.customer, quoteIndex) };
149	      quoteIndex++;
150	      return result;
151	    }),
152	  };
153	};
